// ---- JSON Parsing with Gson ----
// Dependencies:
// implementation("com.squareup.retrofit2:converter-gson:2.9.0")
// implementation("com.google.code.gson:gson:2.10.1")

// ---- Data models with Gson annotations ----
data class User(
    @SerializedName("id")
    val id: Int,

    @SerializedName("name")
    val name: String,

    @SerializedName("username")
    val username: String,

    @SerializedName("email")
    val email: String,

    @SerializedName("address")
    val address: Address,

    @SerializedName("phone")
    val phone: String,

    @SerializedName("website")
    val website: String,

    @SerializedName("company")
    val company: Company
)

data class Address(
    @SerializedName("street")
    val street: String,

    @SerializedName("suite")
    val suite: String,

    @SerializedName("city")
    val city: String,

    @SerializedName("zipcode")
    val zipcode: String,

    @SerializedName("geo")
    val geo: Geo
)

data class Geo(
    @SerializedName("lat")
    val lat: String,

    @SerializedName("lng")
    val lng: String
)

data class Company(
    @SerializedName("name")
    val name: String,

    @SerializedName("catchPhrase")
    val catchPhrase: String,

    @SerializedName("bs")
    val bs: String
)

// ---- Custom Gson instance ----
object GsonClient {
    private val gson = GsonBuilder()
        .setLenient()
        .setPrettyPrinting()
        .create()

    fun toJson(obj: Any): String = gson.toJson(obj)

    fun <T> fromJson(json: String, classOfT: Class<T>): T = gson.fromJson(json, classOfT)

    fun <T> fromJson(json: String, type: Type): T = gson.fromJson(json, type)
}

// ---- Retrofit with Gson ----
interface UserApiService {
    @GET("users")
    suspend fun getUsers(): List<User>

    @GET("users/{id}")
    suspend fun getUser(@Path("id") id: Int): User
}

object RetrofitGsonClient {
    private const val BASE_URL = "https://jsonplaceholder.typicode.com/"

    private val gson = GsonBuilder()
        .setDateFormat("yyyy-MM-dd'T'HH:mm:ssZ")
        .create()

    val api: UserApiService = Retrofit.Builder()
        .baseUrl(BASE_URL)
        .addConverterFactory(GsonConverterFactory.create(gson))
        .build()
        .create(UserApiService::class.java)
}

// ---- Manual JSON parsing ----
class JsonParser {
    fun parseUser(json: String): User {
        return GsonClient.fromJson(json, User::class.java)
    }

    fun parseUserList(json: String): List<User> {
        val type = object : TypeToken<List<User>>() {}.type
        return GsonClient.fromJson(json, type)
    }

    fun toJson(user: User): String {
        return GsonClient.toJson(user)
    }
}

// ---- ViewModel with JSON parsing ----
class JsonViewModel : ViewModel() {
    private val parser = JsonParser()

    data class UiState(
        val user: User? = null,
        val users: List<User> = emptyList(),
        val json: String = "",
        val isLoading: Boolean = false,
        val error: String? = null
    )

    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    // ---- Load and parse users ----
    fun loadUsers() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }

            try {
                val users = RetrofitGsonClient.api.getUsers()

                // Convert to JSON for display
                val json = GsonClient.toJson(users)

                _uiState.update { it.copy(
                    users = users,
                    json = json,
                    isLoading = false
                )}
            } catch (e: Exception) {
                _uiState.update { it.copy(
                    error = e.message ?: "Failed to load users",
                    isLoading = false
                )}
            }
        }
    }

    // ---- Load single user ----
    fun loadUser(id: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }

            try {
                val user = RetrofitGsonClient.api.getUser(id)
                val json = GsonClient.toJson(user)

                _uiState.update { it.copy(
                    user = user,
                    json = json,
                    isLoading = false
                )}
            } catch (e: Exception) {
                _uiState.update { it.copy(
                    error = e.message ?: "Failed to load user",
                    isLoading = false
                )}
            }
        }
    }

    // ---- Manual parse ----
    fun parseJson(json: String) {
        try {
            val user = parser.parseUser(json)
            _uiState.update { it.copy(
                user = user,
                json = json,
                error = null
            )}
        } catch (e: Exception) {
            _uiState.update { it.copy(
                error = "Failed to parse JSON: ${e.message}"
            )}
        }
    }

    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }
}

// ---- UI ----
@Composable
fun JsonScreen() {
    val viewModel: JsonViewModel = viewModel()
    val uiState by viewModel.uiState.collectAsState()

    var jsonInput by remember { mutableStateOf("") }

    Scaffold(
        topBar = { TopAppBar { Text("JSON Parsing with Gson") } }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            if (uiState.isLoading) {
                Box(
                    modifier = Modifier.fillMaxWidth().height(50.dp),
                    contentAlignment = Alignment.Center
                ) {
                    CircularProgressIndicator()
                }
            }

            if (uiState.error != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer
                    )
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = uiState.error ?: "",
                            color = MaterialTheme.colorScheme.onErrorContainer
                        )
                        Button(onClick = { viewModel.clearError() }) {
                            Text("Dismiss")
                        }
                    }
                }
            }

            // ---- User display ----
            if (uiState.user != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = "User: ${uiState.user?.name}",
                            style = MaterialTheme.typography.titleLarge
                        )
                        Text("Email: ${uiState.user?.email}")
                        Text("Username: ${uiState.user?.username}")
                        Text("Phone: ${uiState.user?.phone}")
                        Text("Website: ${uiState.user?.website}")
                        Text("Company: ${uiState.user?.company?.name}")
                    }
                }
            }

            // ---- JSON display ----
            if (uiState.json.isNotEmpty()) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = "JSON Output:",
                            style = MaterialTheme.typography.titleMedium
                        )
                        Text(
                            text = uiState.json,
                            style = MaterialTheme.typography.bodySmall,
                            maxLines = 10,
                            overflow = TextOverflow.Ellipsis
                        )
                    }
                }
            }

            // ---- Manual JSON input ----
            OutlinedTextField(
                value = jsonInput,
                onValueChange = { jsonInput = it },
                label = { Text("Enter JSON") },
                modifier = Modifier.fillMaxWidth(),
                minLines = 3,
                maxLines = 5
            )

            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                Button(
                    onClick = { viewModel.parseJson(jsonInput) },
                    modifier = Modifier.weight(1f),
                    enabled = jsonInput.isNotBlank()
                ) {
                    Text("Parse JSON")
                }

                Button(
                    onClick = { jsonInput = "" },
                    modifier = Modifier.weight(1f)
                ) {
                    Text("Clear")
                }
            }

            // ---- Buttons ----
            Button(
                onClick = { viewModel.loadUsers() },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Load Users")
            }

            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                Button(
                    onClick = { viewModel.loadUser(1) },
                    modifier = Modifier.weight(1f)
                ) {
                    Text("User 1")
                }
                Button(
                    onClick = { viewModel.loadUser(2) },
                    modifier = Modifier.weight(1f)
                ) {
                    Text("User 2")
                }
                Button(
                    onClick = { viewModel.loadUser(3) },
                    modifier = Modifier.weight(1f)
                ) {
                    Text("User 3")
                }
            }
        }
    }
}

