data class BrokenUser(
    // 1. No @SerializedName
    val id: Int,  // JSON "id" works, but mismatch if field name changes

    // 2. Wrong type
    val phone: Int,  // JSON has String

    // 3. Non-nullable for optional
    val address: Address,  // Can be null in JSON

    // 4. No default values
    val name: String  // Required, but maybe missing
)

class BrokenJsonViewModel : ViewModel() {
    // 5. No error handling
    fun parseJson(json: String) {
        val user = Gson().fromJson(json, BrokenUser::class.java)
        // Could crash if JSON is invalid
    }

    // 6. Not using try-catch
}

phase2.explanation:
🤖 **Common JSON parsing mistakes and fixes.**

| Mistake | Fix |
|---------|-----|
| No @SerializedName | Add @SerializedName |
| Wrong type | Use correct type |
| Non-nullable optional | Use nullable type |
| No default values | Add default values |
| No error handling | Use try-catch |

**Fixes:**
```kotlin
// 1. Add @SerializedName
@SerializedName("id")
val id: Int

// 2. Use correct type
@SerializedName("phone")
val phone: String

// 3. Use nullable type
val address: Address? = null

// 4. Add default values
val name: String = ""

// 5. Handle errors
try {
    val user = gson.fromJson(json, User::class.java)
} catch (e: Exception) {
    // Handle error
}
```

