package com.example.gson

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import com.google.gson.Gson
import com.google.gson.annotations.SerializedName

// User data class with Gson annotations
data class User(
    @SerializedName("id")
    val id: Int,

    @SerializedName("name")
    val name: String,

    @SerializedName("email")
    val email: String,

    @SerializedName("phone")
    val phone: String? = null
)

@Composable
fun GsonApp() {
    var user by remember { mutableStateOf<User?>(null) }
    var jsonResult by remember { mutableStateOf("") }
    var error by remember { mutableStateOf<String?>(null) }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // ---- Sample JSON ----
        val sampleJson = """
            {
                "id": 1,
                "name": "Hero",
                "email": "hero@example.com",
                "phone": "555-1234"
            }
        """.trimIndent()

        Button(
            onClick = {
                try {
                    error = null
                    val gson = Gson()
                    user = gson.fromJson(sampleJson, User::class.java)
                    jsonResult = gson.toJson(user)
                } catch (e: Exception) {
                    error = "Error: ${e.message}"
                }
            },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Parse JSON")
        }

        if (error != null) {
            Text(
                text = error ?: "",
                color = MaterialTheme.colorScheme.error
            )
        }

        if (user != null) {
            Card(
                modifier = Modifier.fillMaxWidth(),
                elevation = CardDefaults.cardElevation(4.dp)
            ) {
                Column(
                    modifier = Modifier.padding(16.dp),
                    verticalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Text("✅ Parsed User:", style = MaterialTheme.typography.titleMedium)
                    Text("ID: ${user?.id}")
                    Text("Name: ${user?.name}")
                    Text("Email: ${user?.email}")
                    Text("Phone: ${user?.phone ?: "N/A"}")
                }
            }

            Card(
                modifier = Modifier.fillMaxWidth(),
                elevation = CardDefaults.cardElevation(2.dp)
            ) {
                Column(
                    modifier = Modifier.padding(16.dp)
                ) {
                    Text("JSON Output:", style = MaterialTheme.typography.titleMedium)
                    Text(
                        text = jsonResult,
                        style = MaterialTheme.typography.bodySmall
                    )
                }
            }
        }
    }
}
